using Application.Services.Interface;
using Domain.Models;

namespace Application.Features.App.Chat;

/// <summary>
/// Creates persisted chat system-log messages and broadcasts them over SignalR.
/// </summary>
internal static class ChatSystemMessageWriter
{
    /// <summary>
    /// Builds an in-memory system log message row (not yet saved).
    /// </summary>
    /// <param name="conversationId">Target conversation.</param>
    /// <param name="senderId">Acting user (admin/member who triggered the event).</param>
    /// <param name="text">Localized system text shown in the timeline.</param>
    public static ChatMessage Create(int conversationId, int senderId, string text) =>
        new()
        {
            ConversationId = conversationId,
            SenderId = senderId,
            Text = text
        };

    /// <summary>
    /// Persists a system log message and notifies connected clients.
    /// </summary>
    public static async Task PersistAndNotifyAsync(
        IApplicationDbContext context,
        IChatNotificationService chatNotificationService,
        int conversationId,
        int senderId,
        string text,
        CancellationToken cancellationToken)
    {
        context.ChatMessages.Add(Create(conversationId, senderId, text));
        await context.SaveChangesAsync(cancellationToken);
        await chatNotificationService.SystemMessageAsync(conversationId, text, cancellationToken);
    }
}

