using Application.DTOs.Chat;

namespace Application.Features.App.Chat.Messages.Queries.GetPinnedMessages;

/// <summary>
/// Query to load all active pinned messages for a conversation (pin bar / reload).
/// </summary>
/// <param name="ConversationId">The conversation whose pins are requested.</param>
public record GetPinnedMessagesQuery(int ConversationId)
    : IRequest<Result<List<ChatMessageDto>>>;

using Application.DTOs.Chat;
using Application.Features.App.Chat.Messages;
using Application.Services.Interface;

namespace Application.Features.App.Chat.Messages.Queries.GetPinnedMessages;

/// <summary>
/// Handles <see cref="GetPinnedMessagesQuery"/> by returning pinned messages for the pin bar after reload.
/// </summary>
public class GetPinnedMessagesQueryHandler(
    IApplicationDbContext context,
    ICurrentUserService currentUserService)
    : IRequestHandler<GetPinnedMessagesQuery, Result<List<ChatMessageDto>>>
{
    /// <summary>
    /// Loads active pins for a conversation the caller participates in.
    /// </summary>
    /// <param name="request">The query with conversation id.</param>
    /// <param name="cancellationToken">Cancellation token.</param>
    /// <returns>Pinned message DTOs ordered newest-pin-first.</returns>
    public async Task<Result<List<ChatMessageDto>>> Handle(
        GetPinnedMessagesQuery request,
        CancellationToken cancellationToken)
    {
        try
        {
            int currentUserId = currentUserService.UserId();

            var isMember = await context.ChatParticipants
                .AsNoTracking()
                .AnyAsync(p =>
                    p.ConversationId == request.ConversationId
                    && p.UserId == currentUserId
                    && p.LeftAt == null,
                    cancellationToken);

            if (!isMember)
                return ChatErrors.NotAParticipant;

            var pinnedMessageIds = await context.ChatPinnedMessages
                .AsNoTracking()
                .Where(p => p.ConversationId == request.ConversationId)
                .OrderByDescending(p => p.Id)
                .Take(ChatPinConstants.MaxPinsPerConversation)
                .Select(p => p.MessageId)
                .ToListAsync(cancellationToken);

            if (pinnedMessageIds.Count == 0)
                return Result<List<ChatMessageDto>>.Success([]);

            var messages = await context.ChatMessages
                .IgnoreQueryFilters()
                .AsNoTracking()
                .Where(m => pinnedMessageIds.Contains(m.Id) && !m.IsDeleted)
                .Select(m => new ChatMessageDtoMapper.MessageProjection
                {
                    Id = m.Id,
                    ConversationId = m.ConversationId,
                    SenderId = m.SenderId,
                    SenderName = m.Sender.Name,
                    SenderAvatarUrl = m.Sender.ProfileImage,
                    Text = m.Text,
                    IsDeleted = m.IsDeleted,
                    IsEdited = m.IsEdited,
                    EditedAt = m.EditedAt,
                    SentAt = m.CreateDate,
                    ReplyToMessageId = m.ReplyToMessageId,
                    ReplyToSenderName = m.ReplyToMessage != null ? m.ReplyToMessage.Sender.Name : null,
                    ReplyToText = m.ReplyToMessage != null ? m.ReplyToMessage.Text : null,
                    ReplyToIsDeleted = m.ReplyToMessage != null && m.ReplyToMessage.IsDeleted,
                    ForwardedFromSenderName = m.ForwardedFromSenderName,
                    ForwardedFromSentAt = m.ForwardedFromSentAt,
                    Attachments = m.Attachments.Select(a => new ChatMessageDtoMapper.AttachmentProjection
                    {
                        Id = a.Id,
                        FileName = a.FileName,
                        FileUrl = a.FileUrl,
                        FileSize = a.FileSize,
                        ContentType = a.ContentType
                    }).ToList(),
                    IsPinned = true,
                    IsSavedByMe = context.ChatSavedMessages.Any(s =>
                        s.UserId == currentUserId && s.MessageId == m.Id)
                })
                .ToListAsync(cancellationToken);

            var byId = messages.ToDictionary(m => m.Id);
            var ordered = pinnedMessageIds
                .Where(id => byId.ContainsKey(id))
                .Select(id => ChatMessageDtoMapper.ToDto(byId[id]))
                .ToList();

            return Result<List<ChatMessageDto>>.Success(ordered);
        }
        catch (Exception ex)
        {
            Log.Error($"CQRS (GetPinnedMessages): {ex.Message}", ex);
            return Error.ServerError;
        }
    }
}

using Api.Constants;
using Api.Extentions;
using Application.DTOs.Chat;
using Application.Features.App.Chat.Messages.Queries.GetPinnedMessages;

namespace Api.EndPoint.Chat;

/// <summary>
/// Endpoint for listing pinned messages of a conversation (used after reopen / reload).
/// </summary>
public class GetPinnedMessagesEndPoint : ICarterModule
{
    /// <summary>
    /// Registers the get-pinned-messages route.
    /// </summary>
    /// <param name="app">The endpoint route builder.</param>
    public void AddRoutes(IEndpointRouteBuilder app)
    {
        app.MapGet("/chat/conversations/{conversationId:int}/pinned-messages", async (
            int conversationId,
            ISender sender,
            CancellationToken cancellationToken) =>
        {
            var res = await sender.Send(
                new GetPinnedMessagesQuery(conversationId),
                cancellationToken);

            return res.ToHttpResult();
        })
        .WithName("GetPinnedMessages")
        .WithTags("Chat")
        .Produces<List<ChatMessageDto>>(StatusCodes.Status200OK)
        .ProducesProblem(StatusCodes.Status400BadRequest)
        .WithSummary("Get pinned chat messages")
        .WithDescription("Returns active pinned messages for a conversation so the pin bar can be rebuilt after leaving and returning.")
        .RequireRateLimiting(RateLimitConst.ChatRead)
        .RequireAuthorization()
        .DisableAntiforgery();
    }
}

