$ErrorActionPreference = 'Stop'
$baseUrl = 'http://localhost:5144'
$device = @{
  deviceID = 'BE2A.250530.026.F3'
  deviceName = 'postman-test-device'
  deviceVersion = '16'
  appVersion = '2.113.0'
  platform = 'android'
}
$password = 'Test@12345'

function Login([string]$username) {
  $body = @{ username = $username; password = $password; deviceInfo = $device } | ConvertTo-Json -Depth 5
  $r = Invoke-RestMethod -Uri "$baseUrl/Auth/Login" -Method POST -ContentType 'application/json' -Body $body
  if (-not $r.accessToken) { throw "Login failed for $username" }
  return $r.accessToken
}

function Headers([string]$token) {
  return @{ Authorization = "Bearer $token" }
}

Write-Host '=== AUTH ==='
$t1 = Login 'chattest_sara'
$t2 = Login 'chattest_reza'
$t3 = Login 'chattest_nima'
$null = Login 'chattest_kian'
Write-Host 'AUTH OK (U1-U4)'

Write-Host '=== CREATE GROUP ==='
$form = @{ name = "PersistInt-$(Get-Date -Format yyyyMMddHHmmss)"; memberUserIds = '2747' }
$group = Invoke-RestMethod -Uri "$baseUrl/chat/groups" -Method POST -Headers (Headers $t1) -Form $form
$conversationId = $group.id
if (-not $conversationId) { $conversationId = $group.conversationId }
if (-not $conversationId) { throw "No conversation id: $($group | ConvertTo-Json -Depth 5)" }
Write-Host "conversationId=$conversationId"

Write-Host '=== TOMBSTONE ==='
$msg = Invoke-RestMethod -Uri "$baseUrl/chat/conversations/$conversationId/messages" -Method POST -Headers (Headers $t1) -Form @{ text = "tombstone-$(Get-Date -Format HHmmss)" }
$messageId = $msg.id
if (-not $messageId) { throw "No message id" }
Invoke-RestMethod -Uri "$baseUrl/chat/messages/$messageId" -Method DELETE -Headers (Headers $t1) | Out-Null
$page = Invoke-RestMethod -Uri "$baseUrl/chat/conversations/$conversationId/messages?pageSize=50" -Method GET -Headers (Headers $t2)
$found = $page.messages | Where-Object { $_.id -eq $messageId }
if (-not $found) { throw 'TOMBSTONE FAIL: deleted message missing' }
if ($found.isDeleted -ne $true) { throw 'TOMBSTONE FAIL: isDeleted != true' }
if ($null -ne $found.text) { throw 'TOMBSTONE FAIL: text should be null' }
Write-Host "TOMBSTONE=True messageId=$messageId"

Write-Host '=== SYSTEM LOG ==='
$addBody = @{ userIds = @(2748) } | ConvertTo-Json
Invoke-RestMethod -Uri "$baseUrl/chat/groups/$conversationId/members" -Method POST -Headers (Headers $t1) -ContentType 'application/json' -Body $addBody | Out-Null
$page2 = Invoke-RestMethod -Uri "$baseUrl/chat/conversations/$conversationId/messages?pageSize=50" -Method GET -Headers (Headers $t1)
$sys = $page2.messages | Where-Object { $_.text -and ($_.text -like '*Nima*' -or $_.text -like '*اضافه*') } | Select-Object -First 1
if (-not $sys) {
  # fallback: any recent message with text containing member-add pattern
  $sys = $page2.messages | Where-Object { $_.text -and $_.senderId -eq 2746 -and $_.text.Length -gt 5 -and $_.id -gt $messageId } | Select-Object -Last 1
}
if (-not $sys) { throw "SYSTEM_LOG FAIL. Sample texts: $(($page2.messages | Select-Object -ExpandProperty text | Where-Object { $_ }) -join ' | ')" }
Write-Host "SYSTEM_LOG=True text=$($sys.text)"

Write-Host '=== PIN RELOAD ==='
$pinMsg = Invoke-RestMethod -Uri "$baseUrl/chat/conversations/$conversationId/messages" -Method POST -Headers (Headers $t1) -Form @{ text = "pin-$(Get-Date -Format HHmmss)" }
$pinnedMessageId = $pinMsg.id
# try common pin routes
$pinOk = $false
$pinRoutes = @(
  "$baseUrl/chat/conversations/$conversationId/messages/$pinnedMessageId/pin",
  "$baseUrl/chat/messages/$pinnedMessageId/pin",
  "$baseUrl/chat/conversations/$conversationId/pins"
)
foreach ($route in $pinRoutes) {
  try {
    Invoke-RestMethod -Uri $route -Method POST -Headers (Headers $t1) | Out-Null
    $pinOk = $true
    Write-Host "PIN via $route"
    break
  } catch {
    Write-Host "PIN try fail $route : $($_.Exception.Message)"
  }
}
if (-not $pinOk) { throw 'PIN FAIL: no pin route worked' }

$pins = Invoke-RestMethod -Uri "$baseUrl/chat/conversations/$conversationId/pinned-messages" -Method GET -Headers (Headers $t2)
$pinList = if ($pins -is [System.Array]) { $pins } else { @($pins) }
$hit = $pinList | Where-Object { $_.id -eq $pinnedMessageId }
if (-not $hit) { throw "PIN_RELOAD FAIL. Count=$($pinList.Count)" }
Write-Host "PIN_RELOAD=True pinnedMessageId=$pinnedMessageId"

Write-Host 'ALL_INTEGRATION_OK'

$ErrorActionPreference = 'Stop'
